30	/// Fact-name prefixes reserved for the diff-mode translation (observed in the
31	/// "Reserved prefixes" check, diff mode only).
32	const RESERVED_PREFIXES: &[&str] = &["DiffIntr", "DiffProto"];
33	
34	/// Word-fill width used by the oracle's pretty-printer for the wrapped
35	/// "Reserved prefixes" header (measured empirically: a line breaks before the
36	/// next word once it would exceed column 69).
37	const FILL_WIDTH: usize = 69;
38	
39	/// Reserved fact names (used as protocol facts -> "Reserved names").
40	const RESERVED_FACTS: &[&str] = &["K", "KU", "KD"];
41	/// Special I/O facts handled by the special-fact / Fr checks.
42	const SPECIAL_FACTS: &[&str] = &["In", "Out", "Fr"];
43	
44	fn is_reserved(name: &str) -> bool {
45	    RESERVED_FACTS.contains(&name)
46	}
47	fn is_special(name: &str) -> bool {
48	    SPECIAL_FACTS.contains(&name)
49	}
50	fn is_builtin_factname(name: &str) -> bool {
51	    is_reserved(name) || is_special(name)
52	}
