54	// ---------------------------------------------------------------------------
55	// AST traversal helpers
56	// ---------------------------------------------------------------------------
57	
58	/// The protocol rules of a theory (excludes intruder rules).
59	pub fn protocol_rules(thy: &Theory) -> Vec<&Rule> {
60	    thy.items
61	        .iter()
62	        .filter_map(|it| match it {
63	            TheoryItem::Rule(r) => Some(r),
64	            _ => None,
65	        })
66	        .collect()
67	}
68	
69	fn collect_term_vars(t: &Term, out: &mut Vec<VarSpec>) {
70	    match t {
71	        Term::Var(v) => out.push(v.clone()),
72	        Term::App(_, args) | Term::Pair(args) => {
73	            for a in args {
74	                collect_term_vars(a, out);
75	            }
76	        }
77	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
78	            collect_term_vars(a, out);
79	            collect_term_vars(b, out);
80	        }
81	        Term::PatMatch(inner) => collect_term_vars(inner, out),
82	        _ => {}
83	    }
84	}
85	
86	fn collect_fact_vars(f: &Fact, out: &mut Vec<VarSpec>) {
87	    for a in &f.args {
88	        collect_term_vars(a, out);
89	    }
90	}
91	
92	fn collect_facts_vars(fs: &[Fact], out: &mut Vec<VarSpec>) {
93	    for f in fs {
94	        collect_fact_vars(f, out);
95	    }
96	}
