98	/// Collect public-constant literals (name only) from a term.
99	fn collect_pub_lits(t: &Term, out: &mut Vec<String>) {
100	    match t {
101	        Term::PubLit(s) => out.push(s.clone()),
102	        Term::App(_, args) | Term::Pair(args) => {
103	            for a in args {
104	                collect_pub_lits(a, out);
105	            }
106	        }
107	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
108	            collect_pub_lits(a, out);
109	            collect_pub_lits(b, out);
110	        }
111	        Term::PatMatch(inner) => collect_pub_lits(inner, out),
112	        _ => {}
113	    }
114	}
115	
116	/// Collect fresh-name literals (`~'foo'`) from a term, rendered as the oracle
117	/// prints them.
118	fn collect_fresh_lits(t: &Term, out: &mut Vec<String>) {
119	    match t {
120	        Term::FreshLit(_) => out.push(pp_term(t)),
121	        Term::App(_, args) | Term::Pair(args) => {
122	            for a in args {
123	                collect_fresh_lits(a, out);
124	            }
125	        }
126	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
127	            collect_fresh_lits(a, out);
128	            collect_fresh_lits(b, out);
129	        }
130	        Term::PatMatch(inner) => collect_fresh_lits(inner, out),
131	        _ => {}
132	    }
133	}
134	
135	/// Collect maximal multiplication (`*`) subterms of a term, rendered as the
136	/// oracle prints them. A product is maximal: its own operands are not
137	/// descended into.
138	fn collect_mult_terms(t: &Term, out: &mut Vec<String>) {
139	    if let Term::BinOp(BinOp::Mult, _, _) = t {
140	        out.push(pp_term(t));
141	        return;
142	    }
143	    match t {
144	        Term::App(_, args) | Term::Pair(args) => {
145	            for a in args {
146	                collect_mult_terms(a, out);
147	            }
148	        }
149	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
150	            collect_mult_terms(a, out);
151	            collect_mult_terms(b, out);
152	        }
153	        Term::PatMatch(inner) => collect_mult_terms(inner, out),
154	        _ => {}
155	    }
156	}
