158	/// Indent every line of a (possibly multi-line) block by `n` spaces.
159	fn indent_block(s: &str, n: usize) -> String {
160	    let pad = " ".repeat(n);
161	    s.lines()
162	        .map(|l| format!("{}{}", pad, l))
163	        .collect::<Vec<_>>()
164	        .join("\n")
165	}
166	
167	/// Word-fill (Wadler/Leijen `fillSep`) at the given `width` with a leading
168	/// `indent` of spaces on every line. A word is pushed onto the current line
169	/// while it fits (column + 1 + word <= width), otherwise a new line begins.
170	fn fill_words(words: &[String], indent: usize, width: usize) -> String {
171	    let pad = " ".repeat(indent);
172	    let mut lines: Vec<String> = Vec::new();
173	    let mut cur = String::new();
174	    let mut col = 0usize;
175	    for w in words {
176	        let wlen = w.chars().count();
177	        if cur.is_empty() {
178	            cur = format!("{}{}", pad, w);
179	            col = indent + wlen;
180	        } else if col + 1 + wlen <= width {
181	            cur.push(' ');
182	            cur.push_str(w);
183	            col += 1 + wlen;
184	        } else {
185	            lines.push(std::mem::take(&mut cur));
186	            cur = format!("{}{}", pad, w);
187	            col = indent + wlen;
188	        }
189	    }
190	    if !cur.is_empty() {
191	        lines.push(cur);
192	    }
193	    lines.join("\n")
194	}
195	
196	fn var_needs_binding(v: &VarSpec) -> bool {
197	    matches!(
198	        v.sort,
199	        SortHint::Fresh | SortHint::Msg | SortHint::Untagged | SortHint::Nat
200	    )
201	}
202	
203	fn var_key(v: &VarSpec) -> (String, u64, i32) {
204	    (v.name.clone(), v.idx, sort_rank(v.sort))
205	}
206	
207	fn sort_rank(s: SortHint) -> i32 {
208	    match s {
209	        SortHint::Msg => 0,
210	        SortHint::Pub => 1,
211	        SortHint::Fresh => 2,
212	        SortHint::Node => 3,
213	        SortHint::Nat => 4,
214	        SortHint::Untagged => 5,
215	        SortHint::Suffix(_) => 6,
216	    }
217	}
218	
219	fn dedup_vars(mut vs: Vec<VarSpec>) -> Vec<VarSpec> {
220	    vs.sort_by_key(var_key);
221	    vs.dedup_by_key(|v| var_key(v));
222	    vs
223	}
