225	// ---------------------------------------------------------------------------
226	// 1. Unbound variables
227	// ---------------------------------------------------------------------------
228	pub fn unbound_variables(thy: &Theory) -> Vec<WfError> {
229	    let mut entries: Vec<String> = Vec::new();
230	    for r in protocol_rules(thy) {
231	        // Bound = variables in premises plus let-bound variables.
232	        let mut bound: Vec<VarSpec> = Vec::new();
233	        collect_facts_vars(&r.premises, &mut bound);
234	        for lb in &r.let_block {
235	            collect_term_vars(&lb.var, &mut bound);
236	        }
237	        let bound: std::collections::HashSet<(String, u64, i32)> =
238	            bound.iter().map(var_key).collect();
239	
240	        // Used = variables in actions, conclusions, embedded restrictions,
241	        // and the right-hand-sides of let bindings.
242	        let mut used: Vec<VarSpec> = Vec::new();
243	        collect_facts_vars(&r.actions, &mut used);
244	        collect_facts_vars(&r.conclusions, &mut used);
245	        for lb in &r.let_block {
246	            collect_term_vars(&lb.value, &mut used);
247	        }
248	
249	        let mut unbound: Vec<VarSpec> = used
250	            .into_iter()
251	            .filter(var_needs_binding)
252	            .filter(|v| !bound.contains(&var_key(v)))
253	            .collect();
254	        unbound = dedup_vars(unbound);
255	        // Report order: by base name then index.
256	        unbound.sort_by(|a, b| a.name.cmp(&b.name).then(a.idx.cmp(&b.idx)));
257	
258	        if !unbound.is_empty() {
259	            let names: Vec<String> = unbound.iter().map(pp_var).collect();
260	            entries.push(format!(
261	                "  rule `{}' has unbound variables: \n    {}",
262	                r.name,
263	                names.join(", ")
264	            ));
265	        }
266	    }
267	    if entries.is_empty() {
268	        vec![]
269	    } else {
270	        vec![WfError::new(T_UNBOUND, entries.join("\n  \n"))]
271	    }
272	}
273	
274	// ---------------------------------------------------------------------------
275	// 3. Variable with mismatching sorts or capitalization
276	// ---------------------------------------------------------------------------
277	pub fn mismatching_sorts(thy: &Theory) -> Vec<WfError> {
278	    let mut rule_entries: Vec<String> = Vec::new();
279	    for r in protocol_rules(thy) {
280	        let mut vars: Vec<VarSpec> = Vec::new();
281	        collect_facts_vars(&r.premises, &mut vars);
282	        collect_facts_vars(&r.actions, &mut vars);
283	        collect_facts_vars(&r.conclusions, &mut vars);
284	
285	        // Group by lowercased base name; a group with >1 distinct variant
286	        // (prefix+name, ignoring index) is a conflict.
287	        let mut groups: Vec<(String, Vec<String>)> = Vec::new(); // (lc key, variants)
288	        for v in &vars {
289	            let key = v.name.to_lowercase();
290	            let variant = variant_repr(v);
291	            match groups.iter_mut().find(|(k, _)| *k == key) {
292	                Some((_, variants)) => {
293	                    if !variants.contains(&variant) {
294	                        variants.push(variant);
295	                    }
296	                }
297	                None => groups.push((key, vec![variant])),
298	            }
299	        }
300	        let mut conflicts: Vec<Vec<String>> = groups
301	            .into_iter()
302	            .filter(|(_, vs)| vs.len() > 1)
303	            .map(|(_, mut vs)| {
304	                vs.sort();
305	                vs
306	            })
307	            .collect();
308	        if conflicts.is_empty() {
309	            continue;
310	        }
311	        // deterministic ordering of groups within a rule
312	        conflicts.sort();
313	        let mut body = format!("  rule `{}': ", r.name);
314	        for (i, variants) in conflicts.iter().enumerate() {
315	            body.push_str(&format!("\n    {}. {}", i + 1, variants.join(", ")));
316	        }
317	        rule_entries.push(body);
318	    }
319	    if rule_entries.is_empty() {
320	        return vec![];
321	    }
322	    let header = "Possible reasons:\n1. Identifiers are case sensitive, i.e.,'x' and 'X' are considered to be different.\n2. The same holds for sorts:, i.e., '$x', 'x', and '~x' are considered to be different.\n";
323	    let msg = format!("{}\n{}", header, rule_entries.join("\n  \n"));
324	    vec![WfError::new(T_SORTS, msg)]
325	}
326	
327	/// A variable's sort+name representation without the numeric index.
328	fn variant_repr(v: &VarSpec) -> String {
329	    let prefix = match v.sort {
330	        SortHint::Fresh => "~",
331	        SortHint::Pub => "$",
332	        SortHint::Nat => "%",
333	        SortHint::Node => "#",
334	        _ => "",
335	    };
336	    format!("{}{}", prefix, v.name)
337	}
