339	// ---------------------------------------------------------------------------
340	// 4. Reserved names
341	// ---------------------------------------------------------------------------
342	pub fn reserved_names(thy: &Theory) -> Vec<WfError> {
343	    let mut entries: Vec<String> = Vec::new();
344	    for r in protocol_rules(thy) {
345	        // On the left/right the reserved set is {K,KU,KD}; in the middle
346	        // (actions) the I/O facts In/Out/Fr are reserved too (observed z9/z11).
347	        for (facts, phrase, middle) in [
348	            (&r.premises, "left-hand-side", false),
349	            (&r.actions, "the middle", true),
350	            (&r.conclusions, "the right-hand-side", false),
351	        ] {
352	            let hits: Vec<&Fact> = facts
353	                .iter()
354	                .filter(|f| is_reserved(&f.name) || (middle && is_special(&f.name)))
355	                .collect();
356	            if hits.is_empty() {
357	                continue;
358	            }
359	            let rendered: Vec<String> = hits.iter().map(|f| pp_fact(f)).collect();
360	            entries.push(format!(
361	                "  Rule `{}' contains facts with reserved names on {}:\n    {}",
362	                r.name,
363	                phrase,
364	                rendered.join(", ")
365	            ));
366	        }
367	    }
368	    if entries.is_empty() {
369	        vec![]
370	    } else {
371	        vec![WfError::new(T_RESERVED, entries.join("\n  \n"))]
372	    }
373	}
