375	// ---------------------------------------------------------------------------
376	// 5. Fr facts must only use a fresh- or a msg-variable
377	// ---------------------------------------------------------------------------
378	pub fn fr_facts(thy: &Theory) -> Vec<WfError> {
379	    let mut entries: Vec<String> = Vec::new();
380	    for r in protocol_rules(thy) {
381	        for facts in [&r.premises, &r.conclusions] {
382	            for f in facts {
383	                if f.name != "Fr" {
384	                    continue;
385	                }
386	                let ok = f.args.len() == 1
387	                    && matches!(
388	                        &f.args[0],
389	                        Term::Var(v) if matches!(v.sort, SortHint::Fresh | SortHint::Msg | SortHint::Untagged)
390	                    );
391	                if !ok {
392	                    entries.push(format!("  rule `{}' fact: {}", r.name, pp_fact(f)));
393	                }
394	            }
395	        }
396	    }
397	    if entries.is_empty() {
398	        vec![]
399	    } else {
400	        vec![WfError::new(T_FR, entries.join("\n  \n"))]
401	    }
402	}
403	
404	// ---------------------------------------------------------------------------
405	// 6. Special facts (disallowed I/O facts in wrong position)
406	// ---------------------------------------------------------------------------
407	pub fn special_facts(thy: &Theory) -> Vec<WfError> {
408	    let mut entries: Vec<String> = Vec::new();
409	    for r in protocol_rules(thy) {
410	        // Premise side: `Out` is disallowed.
411	        let lhs: Vec<String> = r
412	            .premises
413	            .iter()
414	            .filter(|f| f.name == "Out")
415	            .map(|f| pp_fact(f))
416	            .collect();
417	        if !lhs.is_empty() {
418	            entries.push(format!(
419	                "  rule `{}' uses disallowed facts on left-hand-side:\n    {}",
420	                r.name,
421	                lhs.join(", ")
422	            ));
423	        }
424	        // Conclusion side: `In` and `Fr` are disallowed.
425	        let rhs: Vec<String> = r
426	            .conclusions
427	            .iter()
428	            .filter(|f| f.name == "In" || f.name == "Fr")
429	            .map(|f| pp_fact(f))
430	            .collect();
431	        if !rhs.is_empty() {
432	            entries.push(format!(
433	                "  rule `{}' uses disallowed facts on right-hand-side:\n    {}",
434	                r.name,
435	                rhs.join(", ")
436	            ));
437	        }
438	    }
439	    if entries.is_empty() {
440	        vec![]
441	    } else {
442	        vec![WfError::new(T_SPECIAL, entries.join("\n  \n"))]
443	    }
444	}
