447	// 7 & 8. Fact arity / multiplicity issues
448	// ---------------------------------------------------------------------------
449	
450	struct FactUse {
451	    label: &'static str, // "Rule" or "Lemma"
452	    owner: String,       // rule/lemma name
453	    arity: usize,
454	    persistent: bool,
455	    render: String, // pp_fact for rules; raw Haskell `Fact {..}` show for lemmas
456	}
457	
458	/// Raw Haskell `Show` of a lemma-sourced fact, as the oracle prints it in the
459	/// arity/multiplicity blocks (observed r3_lemarity / r3_lemmult):
460	///   Fact {factTag = ProtoFact Linear "Act" 2, factAnnotations = fromList [],
461	///         factTerms = [Bound 2,Bound 1]}
462	/// `factTerms` uses the same de Bruijn / Free rendering as the Formula-terms
463	/// check (the binder `stack` is the quantifier context at the atom).
464	fn show_haskell_fact(f: &Fact, stack: &[String]) -> String {
465	    let mult = if f.persistent { "Persistent" } else { "Linear" };
466	    let terms: Vec<String> = f.args.iter().map(|a| show_wf_term(a, stack)).collect();
467	    format!(
468	        "Fact {{factTag = ProtoFact {} \"{}\" {}, factAnnotations = fromList [], factTerms = [{}]}}",
469	        mult,
470	        f.name,
471	        f.args.len(),
472	        terms.join(",")
473	    )
474	}
475	
476	/// Collect action-fact uses from a lemma formula (label "Lemma"), tracking the
477	/// quantifier binder stack for the de Bruijn rendering of the fact terms.
478	fn gather_formula_facts(
479	    f: &Formula,
480	    stack: &mut Vec<String>,
481	    owner: &str,
482	    out: &mut Vec<(String, FactUse)>,
483	) {
484	    match f {
485	        Formula::False | Formula::True => {}
486	        Formula::Atom(Atom::Action(fact, _)) => {
487	            out.push((
488	                fact.name.clone(),
489	                FactUse {
490	                    label: "Lemma",
491	                    owner: owner.to_string(),
492	                    arity: fact.args.len(),
493	                    persistent: fact.persistent,
494	                    render: show_haskell_fact(fact, stack),
495	                },
496	            ));
497	        }
498	        Formula::Atom(_) => {}
499	        Formula::Not(g) => gather_formula_facts(g, stack, owner, out),
500	        Formula::And(a, b)
501	        | Formula::Or(a, b)
502	        | Formula::Implies(a, b)
503	        | Formula::Iff(a, b) => {
504	            gather_formula_facts(a, stack, owner, out);
505	            gather_formula_facts(b, stack, owner, out);
506	        }
507	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
508	            let n = vs.len();
509	            for v in vs {
510	                stack.push(v.name.clone());
511	            }
512	            gather_formula_facts(g, stack, owner, out);
513	            for _ in 0..n {
514	                stack.pop();
515	            }
516	        }
517	    }
518	}
519	
520	/// Gather every fact occurrence in the theory (name -> uses) in source order.
521	/// Protocol rules contribute their premise/action/conclusion facts (rendered by
522	/// the term pretty-printer); lemmas contribute their formula action facts
523	/// (rendered as the raw Haskell `Fact {..}` show). Restrictions do NOT
524	/// contribute (observed r3_restrarity: a restriction action arity mismatch is
525	/// silent).
526	fn gather_fact_uses(thy: &Theory) -> Vec<(String, Vec<FactUse>)> {
527	    let mut map: Vec<(String, Vec<FactUse>)> = Vec::new();
528	    let push = |name: String, u: FactUse, map: &mut Vec<(String, Vec<FactUse>)>| {
529	        match map.iter_mut().find(|(n, _)| *n == name) {
530	            Some((_, uses)) => uses.push(u),
531	            None => map.push((name, vec![u])),
532	        }
533	    };
534	    for it in &thy.items {
535	        match it {
536	            TheoryItem::Rule(r) => {
537	                for facts in [&r.premises, &r.actions, &r.conclusions] {
538	                    for f in facts {
539	                        push(
540	                            f.name.clone(),
541	                            FactUse {
542	                                label: "Rule",
543	                                owner: r.name.clone(),
544	                                arity: f.args.len(),
545	                                persistent: f.persistent,
546	                                render: pp_fact(f),
547	                            },
548	                            &mut map,
549	                        );
550	                    }
551	                }
552	            }
553	            TheoryItem::Lemma(l) => {
554	                let mut stack: Vec<String> = Vec::new();
555	                let mut uses: Vec<(String, FactUse)> = Vec::new();
556	                gather_formula_facts(&l.formula, &mut stack, &l.name, &mut uses);
557	                for (name, u) in uses {
558	                    push(name, u, &mut map);
559	                }
560	            }
561	            _ => {}
562	        }
563	    }
564	    map
565	}
