567	fn render_fact_blocks(conflicts: &[(String, Vec<String>)], intro1: &str, intro2: &str) -> String {
568	    // conflicts: (lowercased fact name, item lines) already ordered.
569	    let mut body = format!("{}\n{}\n  ", intro1, intro2);
570	    for (i, (lname, items)) in conflicts.iter().enumerate() {
571	        let block = format!("  Fact `{}':\n\n{}\n  ", lname, items.join("\n    \n"));
572	        if i == 0 {
573	            body.push_str("\n\n");
574	        } else {
575	            body.push('\n');
576	        }
577	        body.push_str(&block);
578	    }
579	    body
580	}
