582	// ---------------------------------------------------------------------------
583	// Fact capitalization issues (precedes Fact arity issues)
584	// ---------------------------------------------------------------------------
585	// Fact names that are equal under ASCII-lowercasing but differ in their exact
586	// spelling (e.g. `Send` vs `SEND`) are distinct facts. Reported like the arity
587	// block, but EVERY occurrence is listed (no per-(rule,cap) deduplication -
588	// observed r3_capord: `Send` twice in one rule yields two items).
589	pub fn fact_capitalization(thy: &Theory) -> Vec<WfError> {
590	    struct Occ {
591	        name: String,
592	        rule: String,
593	        pp: String,
594	    }
595	    let mut occ: Vec<Occ> = Vec::new();
596	    for r in protocol_rules(thy) {
597	        for facts in [&r.premises, &r.actions, &r.conclusions] {
598	            for f in facts {
599	                occ.push(Occ {
600	                    name: f.name.clone(),
601	                    rule: r.name.clone(),
602	                    pp: pp_fact(f),
603	                });
604	            }
605	        }
606	    }
607	    // Group by lowercased name, preserving first-seen order.
608	    let mut groups: Vec<(String, Vec<&Occ>)> = Vec::new();
609	    for o in &occ {
610	        let key = o.name.to_lowercase();
611	        match groups.iter_mut().find(|(k, _)| *k == key) {
612	            Some((_, v)) => v.push(o),
613	            None => groups.push((key, vec![o])),
614	        }
615	    }
616	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
617	    for (key, os) in &groups {
618	        let distinct: std::collections::BTreeSet<&String> = os.iter().map(|o| &o.name).collect();
619	        if distinct.len() < 2 {
620	            continue; // no capitalization conflict
621	        }
622	        let items: Vec<String> = os
623	            .iter()
624	            .enumerate()
625	            .map(|(i, o)| {
626	                format!(
627	                    "    {}. Rule `{}', capitalization \"{}\"\n         {}",
628	                    i + 1,
629	                    o.rule,
630	                    o.name,
631	                    o.pp
632	                )
633	            })
634	            .collect();
635	        conflicts.push((key.clone(), items));
636	    }
637	    if conflicts.is_empty() {
638	        return vec![];
639	    }
640	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
641	    let msg = render_fact_blocks(
642	        &conflicts,
643	        "Fact names are case-sensitive, different capitalizations are considered as different facts, i.e., Fact() is different from FAct(). ",
644	        "Check the capitalization of your fact names.",
645	    );
646	    vec![WfError::new(T_FACT_CAP, msg)]
647	}
