649	pub fn fact_arity(thy: &Theory) -> Vec<WfError> {
650	    let uses = gather_fact_uses(thy);
651	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
652	    for (name, us) in &uses {
653	        let arities: std::collections::BTreeSet<usize> = us.iter().map(|u| u.arity).collect();
654	        if arities.len() < 2 {
655	            continue;
656	        }
657	        // one item per distinct (label, owner, arity), first render kept.
658	        let mut seen: Vec<(&str, String, usize)> = Vec::new();
659	        let mut items: Vec<String> = Vec::new();
660	        for u in us {
661	            let k = (u.label, u.owner.clone(), u.arity);
662	            if seen.contains(&k) {
663	                continue;
664	            }
665	            seen.push(k);
666	            let n = items.len() + 1;
667	            items.push(format!(
668	                "    {}. {} `{}', arity {}\n         {}",
669	                n, u.label, u.owner, u.arity, u.render
670	            ));
671	        }
672	        conflicts.push((name.to_lowercase(), items));
673	    }
674	    if conflicts.is_empty() {
675	        return vec![];
676	    }
677	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
678	    let msg = render_fact_blocks(
679	        &conflicts,
680	        "Same fact is used with different arities, i.e., Fact('A','B') is different from Fact('A'). ",
681	        "Check the arguments of your facts.",
682	    );
683	    vec![WfError::new(T_ARITY, msg)]
684	}
