750	pub fn fact_lhs_occur_no_rhs(thy: &Theory) -> Vec<WfError> {
751	    let mut lhs: Vec<FactId> = Vec::new();
752	    let mut rhs: Vec<FactId> = Vec::new();
753	    for r in protocol_rules(thy) {
754	        for f in &r.premises {
755	            if is_builtin_factname(&f.name) {
756	                continue;
757	            }
758	            lhs.push(FactId {
759	                name: f.name.clone(),
760	                arity: f.args.len(),
761	                persistent: f.persistent,
762	                rule: r.name.clone(),
763	            });
764	        }
765	        for f in &r.conclusions {
766	            if is_builtin_factname(&f.name) {
767	                continue;
768	            }
769	            rhs.push(FactId {
770	                name: f.name.clone(),
771	                arity: f.args.len(),
772	                persistent: f.persistent,
773	                rule: r.name.clone(),
774	            });
775	        }
776	    }
777	    let rhs_idents: std::collections::HashSet<(String, usize, bool)> =
778	        rhs.iter().map(|f| f.ident()).collect();
779	
780	    // LHS-only identities, first occurrence, in source order.
781	    let mut seen: Vec<(String, usize, bool)> = Vec::new();
782	    let mut items: Vec<String> = Vec::new();
783	    for f in &lhs {
784	        if rhs_idents.contains(&f.ident()) || seen.contains(&f.ident()) {
785	            continue;
786	        }
787	        seen.push(f.ident());
788	        let n = items.len() + 1;
789	        let mut line = format!("  {}. {}", n, f.render());
790	        if let Some(sugg) = nearest_rhs(&f.name, &rhs) {
791	            line.push_str(&format!(". Perhaps you want to use the fact {}", sugg.render()));
792	        }
793	        items.push(line);
794	    }
795	    if items.is_empty() {
796	        vec![]
797	    } else {
798	        vec![WfError::new(T_LHSRHS, items.join("\n  \n"))]
799	    }
800	}
