802	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
803	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
804	    let mut best: Option<(usize, &FactId)> = None;
805	    for f in rhs {
806	        let d = edit_distance(name, &f.name);
807	        match best {
808	            Some((bd, _)) if d >= bd => {}
809	            _ => best = Some((d, f)),
810	        }
811	    }
812	    match best {
813	        Some((d, f)) if d <= 3 => Some(f),
814	        _ => None,
815	    }
816	}
817	
818	fn edit_distance(a: &str, b: &str) -> usize {
819	    let a: Vec<char> = a.chars().collect();
820	    let b: Vec<char> = b.chars().collect();
821	    let mut prev: Vec<usize> = (0..=b.len()).collect();
822	    let mut cur = vec![0usize; b.len() + 1];
823	    for i in 1..=a.len() {
824	        cur[0] = i;
825	        for j in 1..=b.len() {
826	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
827	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
828	        }
829	        std::mem::swap(&mut prev, &mut cur);
830	    }
831	    prev[b.len()]
832	}
