838	pub fn public_names_report(thy: &Theory) -> Vec<WfError> {
839	    let mut pairs: Vec<(String, String)> = Vec::new(); // (constName, ruleName)
840	    for r in protocol_rules(thy) {
841	        let mut names: Vec<String> = Vec::new();
842	        for facts in [&r.premises, &r.actions, &r.conclusions] {
843	            for f in facts {
844	                for a in &f.args {
845	                    collect_pub_lits(a, &mut names);
846	                }
847	            }
848	        }
849	        for n in names {
