859	pub fn public_names_report_from_pairs(pairs: Vec<(String, String)>) -> Vec<WfError> {
860	    // Group by lowercased constant name, preserving first-seen order.
861	    let mut groups: Vec<(String, Vec<(String, String)>)> = Vec::new();
862	    for (name, rule) in &pairs {
863	        let key = name.to_lowercase();
864	        match groups.iter_mut().find(|(k, _)| *k == key) {
865	            Some((_, v)) => v.push((name.clone(), rule.clone())),
866	            None => groups.push((key, vec![(name.clone(), rule.clone())])),
867	        }
868	    }
869	    let mut items: Vec<String> = Vec::new();
870	    for (_, occ) in &groups {
871	        let distinct: std::collections::BTreeSet<&String> = occ.iter().map(|(n, _)| n).collect();
872	        if distinct.len() < 2 {
873	            continue; // no capitalization conflict
874	        }
875	        // Group occurrences by rule, preserving first-seen rule order.
876	        let mut by_rule: Vec<(String, Vec<String>)> = Vec::new();
877	        for (n, rule) in occ {
878	            match by_rule.iter_mut().find(|(rr, _)| rr == rule) {
879	                Some((_, ns)) => {
880	                    if !ns.contains(n) {
881	                        ns.push(n.clone());
882	                    }
883	                }
884	                None => by_rule.push((rule.clone(), vec![n.clone()])),
885	            }
886	        }
887	        let locs: Vec<String> = by_rule
888	            .into_iter()
889	            .map(|(rule, mut ns)| {
890	                ns.sort();
891	                let quoted: Vec<String> = ns.iter().map(|n| format!("'{}'", n)).collect();
892	                format!("rule \"{}\":  name {}", rule, quoted.join(", "))
893	            })
894	            .collect();
895	        let n = items.len() + 1;
896	        items.push(format!("  {}. {}", n, locs.join(", ")));
897	    }
898	    if items.is_empty() {
899	        return vec![];
900	    }
901	    let header = "Identifiers are case-sensitive, mismatched capitalizations are considered as different, i.e., 'ID' is different from 'id'. Check the capitalization of your identifiers.";
902	    let msg = format!("{}\n\n{}", header, items.join("\n  \n"));
903	    vec![WfError::new(T_PUBNAMES, msg)]
904	}
