906	// ---------------------------------------------------------------------------
907	// 10. Formula terms (ill-formed terms in lemma / restriction formulas)
908	// ---------------------------------------------------------------------------
909	// A lemma/restriction formula may only use terms built from public constants
910	// and BOUND node/message variables via non-reducible function symbols. A term
911	// is reported "of the wrong form" if it contains a FREE variable or a REDUCIBLE
912	// function symbol. The whole offending top-level term (each argument of each
913	// atom) is reported, rendered in the oracle's raw term representation:
914	//   - a bound variable  -> `Bound N` (de Bruijn: 0 = innermost binder)
915	//   - a free  variable  -> `Free <pp_var>`  (keeps the sort prefix)
916	//   - a function app    -> `f(a,b)`  (args comma-joined, NO space)
917	//   - a tuple           -> `pair(a,pair(b,c))` (right-nested binary pairs)
918	//   - a public constant -> `'name'`
919	// The set of reducible function symbol names is caller-supplied (the caller
920	// computes reducibility from the equation theory / Maude); this module only
921	// consumes it. `formula_terms` is the zero-reducible-symbols convenience
922	// wrapper (free variables only). See BEHAVIOR.md.
923	
924	const FORMULA_TERMS_HELP: &str = "  The only allowed terms are public constants and bound node and\n  message variables. If you encounter free message variables, then\n  you might have forgotten a #-prefix. Sort prefixes can only be\n  dropped where this is unambiguous. Moreover, reducible function\n  symbols are disallowed.";
925	
926	/// De Bruijn index of `name` on the binder stack (outermost pushed first): the
927	/// innermost matching binder is 0. `None` if the name is not bound (free).
928	/// Binders are matched by NAME only (see BEHAVIOR.md round-2 fix).
929	fn debruijn_index(stack: &[String], name: &str) -> Option<usize> {
930	    stack
931	        .iter()
932	        .rposition(|b| b == name)
933	        .map(|pos| stack.len() - 1 - pos)
934	}
935	
936	/// Render a term in the oracle's raw "wrong form" representation.
937	fn show_wf_term(t: &Term, stack: &[String]) -> String {
938	    match t {
939	        Term::Var(v) => match debruijn_index(stack, &v.name) {
940	            Some(idx) => format!("Bound {}", idx),
941	            None => format!("Free {}", pp_var(v)),
942	        },
943	        Term::PubLit(s) => format!("'{}'", s),
944	        Term::FreshLit(s) => format!("~'{}'", s),
945	        Term::NatLit(s) => format!("%'{}'", s),
946	        Term::Number(n) => n.to_string(),
947	        Term::NumberOne => "1".to_string(),
948	        Term::NatOne => "%1".to_string(),
949	        Term::DhNeutral => "DH_neutral".to_string(),
950	        Term::App(name, args) => {
951	            if args.is_empty() {
952	                name.clone()
953	            } else {
954	                let parts: Vec<String> = args.iter().map(|a| show_wf_term(a, stack)).collect();
955	                format!("{}({})", name, parts.join(","))
956	            }
957	        }
958	        Term::AlgApp(name, a, b) => {
959	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
960	        }
961	        Term::Pair(items) => show_wf_pair(items, stack),
962	        Term::Diff(a, b) => {
963	            format!("diff({},{})", show_wf_term(a, stack), show_wf_term(b, stack))
964	        }
965	        Term::BinOp(op, a, b) => {
966	            // Raw operator function name (best-effort; AC/DH operators in
967	            // formula terms are rare - see BEHAVIOR.md gaps).
968	            let name = match op {
969	                BinOp::Exp => "exp",
970	                BinOp::Mult => "mult",
971	                BinOp::Union => "union",
972	                BinOp::Xor => "xor",
973	                BinOp::NatPlus => "tadd",
974	            };
975	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
976	        }
977	        Term::PatMatch(inner) => show_wf_term(inner, stack),
978	    }
979	}
980	
981	/// Render a tuple as right-nested binary `pair(...)` applications.
982	fn show_wf_pair(items: &[Term], stack: &[String]) -> String {
983	    match items {
984	        [] => "pair".to_string(),
985	        [only] => show_wf_term(only, stack),
986	        [head, rest @ ..] => {
987	            format!("pair({},{})", show_wf_term(head, stack), show_wf_pair(rest, stack))
988	        }
989	    }
990	}
991	
992	/// True iff `t` contains a free variable or a reducible function symbol, i.e.
993	/// the term is "of the wrong form" for a trace formula.
994	fn term_is_ill_formed(t: &Term, stack: &[String], reducible: &std::collections::BTreeSet<String>) -> bool {
995	    match t {
996	        Term::Var(v) => debruijn_index(stack, &v.name).is_none(), // free -> ill
997	        Term::PubLit(_)
998	        | Term::FreshLit(_)
999	        | Term::NatLit(_)
1000	        | Term::Number(_)
1001	        | Term::NumberOne
1002	        | Term::NatOne
1003	        | Term::DhNeutral => false,
1004	        Term::App(name, args) => {
1005	            reducible.contains(name) || args.iter().any(|a| term_is_ill_formed(a, stack, reducible))
1006	        }
1007	        Term::AlgApp(name, a, b) => {
1008	            reducible.contains(name)
1009	                || term_is_ill_formed(a, stack, reducible)
1010	                || term_is_ill_formed(b, stack, reducible)
1011	        }
1012	        Term::Pair(items) => items.iter().any(|a| term_is_ill_formed(a, stack, reducible)),
1013	        Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1014	            term_is_ill_formed(a, stack, reducible) || term_is_ill_formed(b, stack, reducible)
1015	        }
1016	        Term::PatMatch(inner) => term_is_ill_formed(inner, stack, reducible),
1017	    }
1018	}
