1020	/// The argument terms of an atom, in the oracle's reporting order. For an
1021	/// action atom the TEMPORAL variable is reported before the fact arguments
1022	/// (observed via probe r3_actord).
1023	fn atom_terms(a: &Atom) -> Vec<&Term> {
1024	    match a {
1025	        Atom::Eq(x, y) | Atom::Less(x, y) | Atom::LessMset(x, y) | Atom::Subterm(x, y) => {
1026	            vec![x, y]
1027	        }
1028	        Atom::Action(f, t) => {
1029	            let mut v = vec![t];
1030	            v.extend(f.args.iter());
1031	            v
1032	        }
1033	        Atom::Last(t) => vec![t],
1034	        Atom::Pred(f) => f.args.iter().collect(),
1035	    }
1036	}
1037	
1038	/// Walk a formula in source order collecting the RENDERED strings of every
1039	/// ill-formed atom term. Not deduplicated (probe r3_shapes: `x = y & x = y`
1040	/// reports `Free y` twice).
1041	fn collect_ill_terms(
1042	    f: &Formula,
1043	    stack: &mut Vec<String>,
1044	    reducible: &std::collections::BTreeSet<String>,
1045	    out: &mut Vec<String>,
1046	) {
1047	    match f {
1048	        Formula::False | Formula::True => {}
1049	        Formula::Atom(a) => {
1050	            for t in atom_terms(a) {
1051	                if term_is_ill_formed(t, stack, reducible) {
1052	                    out.push(show_wf_term(t, stack));
1053	                }
1054	            }
1055	        }
1056	        Formula::Not(g) => collect_ill_terms(g, stack, reducible, out),
1057	        Formula::And(a, b)
1058	        | Formula::Or(a, b)
1059	        | Formula::Implies(a, b)
1060	        | Formula::Iff(a, b) => {
1061	            collect_ill_terms(a, stack, reducible, out);
1062	            collect_ill_terms(b, stack, reducible, out);
1063	        }
1064	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
1065	            let n = vs.len();
1066	            for v in vs {
1067	                stack.push(v.name.clone());
1068	            }
1069	            collect_ill_terms(g, stack, reducible, out);
1070	            for _ in 0..n {
1071	                stack.pop();
1072	            }
1073	        }
1074	    }
1075	}
