1114	/// Full "Formula terms" check: reports ill-formed terms (free variables and
1115	/// applications of any symbol in `reducible`) in lemma/restriction formulas.
1116	pub fn formula_terms_reducible(
1117	    thy: &Theory,
1118	    reducible: &std::collections::BTreeSet<String>,
1119	) -> Vec<WfError> {
1120	    let mut entries: Vec<String> = Vec::new();
1121	    for it in &thy.items {
1122	        let (entity, name, formula) = match it {
1123	            TheoryItem::Lemma(l) => ("Lemma", &l.name, &l.formula),
1124	            TheoryItem::Restriction(r) | TheoryItem::LegacyAxiom(r) => {
1125	                ("Restriction", &r.name, &r.formula)
1126	            }
1127	            _ => continue,
1128	        };
1129	        let mut stack: Vec<String> = Vec::new();
