1299	fn collect_nat_issues(t: &Term, out: &mut Vec<String>) {
1300	    if let Term::BinOp(BinOp::NatPlus, _, _) = t {
1301	        let term_pp = pp_term(t);
1302	        let mut vs = Vec::new();
1303	        collect_term_vars(t, &mut vs);
1304	        for v in vs {
1305	            if v.sort != SortHint::Nat {
1306	                let entry = format!("  {} in term {} must be of sort nat", pp_var(&v), term_pp);
1307	                if !out.contains(&entry) {
1308	                    out.push(entry);
1309	                }
1310	            }
1311	        }
1312	    }
1313	    // recurse
1314	    match t {
1315	        Term::App(_, args) | Term::Pair(args) => {
1316	            for a in args {
1317	                collect_nat_issues(a, out);
1318	            }
1319	        }
1320	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1321	            collect_nat_issues(a, out);
1322	            collect_nat_issues(b, out);
1323	        }
1324	        Term::PatMatch(inner) => collect_nat_issues(inner, out),
1325	        _ => {}
1326	    }
1327	}
