1332	
1333	pub fn subterm_convergence(thy: &Theory) -> Vec<WfError> {
1334	    let mut bad: Vec<String> = Vec::new();
1335	    for it in &thy.items {
1336	        if let TheoryItem::Equations { convergent, eqs } = it {
1337	            if *convergent {
1338	                continue; // user asserted convergence
1339	            }
1340	            for eq in eqs {
1341	                if !is_subterm(&eq.rhs, &eq.lhs) {
1342	                    bad.push(format!("    {} = {}", pp_term(&eq.lhs), pp_term(&eq.rhs)));
1343	                }
1344	            }
1345	        }
1346	    }
1347	    if bad.is_empty() {
1348	        return vec![];
1349	    }
1350	    let intro = "  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue ";
1351	    let manual = " For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ";
1352	    let msg = format!("{}\n\n{}\n   \n{}", intro, bad.join("\n"), manual);
1353	    vec![WfError::new(T_SUBTERM, msg)]
1354	}
