1409	// Fact names beginning with `DiffIntr`/`DiffProto` are reserved for the diff
1410	// translation. Only emitted for diff-mode theories (observed: silent otherwise).
1411	pub fn reserved_prefixes(thy: &Theory) -> Vec<WfError> {
1412	    if !thy.is_diff {
1413	        return vec![];
1414	    }
1415	    let mut entries: Vec<String> = Vec::new();
1416	    for r in protocol_rules(thy) {
1417	        // Order of collection: premises, actions, conclusions (probe rp_multi).
1418	        let mut hits: Vec<&Fact> = Vec::new();
1419	        for facts in [&r.premises, &r.actions, &r.conclusions] {
1420	            for f in facts {
1421	                if RESERVED_PREFIXES.iter().any(|p| f.name.starts_with(p)) {
1422	                    hits.push(f);
1423	                }
1424	            }
1425	        }
1426	        if hits.is_empty() {
1427	            continue;
1428	        }
1429	        let header = fill_words(&reserved_prefix_header_words(&r.name), 2, FILL_WIDTH);
1430	        let blocks: Vec<String> = hits
1431	            .iter()
1432	            .map(|f| {
1433	                let m = if f.persistent { "Persistent" } else { "Linear" };
1434	                format!(
1435	                    "    {}\n    (ProtoFact {} \"{}\" {},{},{})",
1436	                    pp_fact(f),
1437	                    m,
1438	                    f.name,
1439	                    f.args.len(),
1440	                    f.args.len(),
1441	                    m
1442	                )
1443	            })
1444	            .collect();
1445	        entries.push(format!("{}\n  \n{}", header, blocks.join("\n  \n")));
1446	    }
1447	    if entries.is_empty() {
1448	        vec![]
1449	    } else {
1450	        vec![WfError::new(T_RESERVED_PREFIX, entries.join("\n  \n"))]
1451	    }
1452	}
