1475	// 11 & 12. Left rule / Right rule (diff mode only)
1476	// ---------------------------------------------------------------------------
1477	// A diff rule may carry explicit `left`/`right` projections. Each explicit
1478	// projection must equal the corresponding projection of the parent diff rule
1479	// (diff(a,b) -> a on the left, -> b on the right). When it differs, the rule is
1480	// "inconsistent". For a single rule the left projection is checked first and,
1481	// if inconsistent, the right is not reported (observed via probe diff_both).
1482	pub fn diff_left_right(thy: &Theory) -> Vec<WfError> {
1483	    if !thy.is_diff {
1484	        return vec![];
1485	    }
1486	    let mut left_entries: Vec<String> = Vec::new();
1487	    let mut right_entries: Vec<String> = Vec::new();
1488	    for r in protocol_rules(thy) {
1489	        if let Some((left, right)) = &r.left_right {
1490	            if !rule_matches_projection(r, left, true) {
1491	                left_entries.push(inconsistent_entry("left", left, r));
1492	            } else if !rule_matches_projection(r, right, false) {
1493	                right_entries.push(inconsistent_entry("right", right, r));
1494	            }
1495	        }
1496	    }
1497	    let mut out = Vec::new();
1498	    if !left_entries.is_empty() {
1499	        out.push(WfError::new(T_LEFT, left_entries.join("\n  \n")));
1500	    }
1501	    if !right_entries.is_empty() {
1502	        out.push(WfError::new(T_RIGHT, right_entries.join("\n  \n")));
1503	    }
1504	    out
1505	}
