1507	fn inconsistent_entry(side: &str, explicit: &Rule, parent: &Rule) -> String {
1508	    format!(
1509	        "  Inconsistent {} rule\n{}\n  \n  w.r.t.\n  \n{}",
1510	        side,
1511	        indent_block(&pp_rule(explicit), 4),
1512	        indent_block(&pp_rule(parent), 4)
1513	    )
1514	}
1515	
1516	/// True iff the explicit rule's fact lists equal the parent rule's projection.
1517	fn rule_matches_projection(parent: &Rule, explicit: &Rule, left: bool) -> bool {
1518	    facts_pp(&project_facts(&parent.premises, left)) == facts_pp(&explicit.premises)
1519	        && facts_pp(&project_facts(&parent.actions, left)) == facts_pp(&explicit.actions)
1520	        && facts_pp(&project_facts(&parent.conclusions, left)) == facts_pp(&explicit.conclusions)
1521	}
1522	
1523	fn facts_pp(fs: &[Fact]) -> String {
1524	    fs.iter().map(pp_fact).collect::<Vec<_>>().join(", ")
1525	}
1526	
1527	fn project_facts(fs: &[Fact], left: bool) -> Vec<Fact> {
1528	    fs.iter().map(|f| project_fact(f, left)).collect()
1529	}
1530	
1531	fn project_fact(f: &Fact, left: bool) -> Fact {
1532	    Fact {
1533	        persistent: f.persistent,
1534	        name: f.name.clone(),
1535	        args: f.args.iter().map(|a| project_term(a, left)).collect(),
1536	        annotations: f.annotations.clone(),
1537	    }
1538	}
