1540	/// Project a diff term to one side: `diff(a, b)` becomes `a` (left) or `b`
1541	/// (right); all other terms are structurally mapped.
1542	fn project_term(t: &Term, left: bool) -> Term {
1543	    match t {
1544	        Term::Diff(a, b) => project_term(if left { a } else { b }, left),
1545	        Term::App(name, args) => {
1546	            Term::App(name.clone(), args.iter().map(|a| project_term(a, left)).collect())
1547	        }
1548	        Term::Pair(args) => Term::Pair(args.iter().map(|a| project_term(a, left)).collect()),
1549	        Term::AlgApp(name, a, b) => Term::AlgApp(
1550	            name.clone(),
1551	            Box::new(project_term(a, left)),
1552	            Box::new(project_term(b, left)),
1553	        ),
1554	        Term::BinOp(op, a, b) => Term::BinOp(
1555	            *op,
1556	            Box::new(project_term(a, left)),
1557	            Box::new(project_term(b, left)),
1558	        ),
1559	        Term::PatMatch(inner) => Term::PatMatch(Box::new(project_term(inner, left))),
1560	        other => other.clone(),
1561	    }
1562	}
